<template>
    <section>
        <loader :is-visible="isLoading"></loader>
        <tg-list 
            ref="tgList" 
            :listType="['List']" 
            :IsShowAction="true" 
            :showCheckBox="true" 
            ModuleName="BillingValidationData"
            SubModuleCode="FlagRecords" 
            IdentityColumn="COLUMN_ID" 
            :HeaderText="$t('FlagRecords')" 
            :ListData="ListingData"
            :HeaderData="Headers" 
            :widgets="widgets" 
            :HeaderButtons="Buttons" 
            :TotalRecords="TotalRecords"
            :RenderRowActionMethod="renderActions" 
            :ListDataCallBackFunction="FetchFlagRecords" 
            :SortExp="SortExp"
            :SortBy="SortBy" 
            :NorecordfoundText="$t('NoRecordfound')" 
            v-on:PagerButtonClick="pagerMethod"
            v-on:HeaderButtonClick="commonHeaderButtonClick" 
            v-on:SortdataButtonClick="sortdata"
            :LegendArray="LegendArray" 
            v-on:LeftsearchButtonClick="leftCommonSearch"
            v-on:ActionButtonClick="actionButtonClick"
            :SearchFields="leftSearchFields"
            SearchPosition="top"
            :CurrentPageNumber="PageNumber"
            :routeInfo="$router"
        >
            <template v-slot:slotdata="{ data }">
                <template v-if="data.column.COLUMN_NAME == 'FLAG_REASON'">
                    <span 
                        :class="getFlagClass(data.row.FLAG)" 
                        :title="data.row.FLAG_REASON"
                    >
                        {{ data.row.FLAG_REASON }}
                    </span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'TRANSMIT_DATE'">
                    <span v-if="data.row.TRANSMIT_DATE">
                     {{ $options.filters.formatDate(data.row.TRANSMIT_DATE) }}   
                    </span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'WORK_DATE'">
                    <span v-if="data.row.WORK_DATE">
                    {{ $options.filters.formatDate(data.row.WORK_DATE) }}   
                    </span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'PROCESS_DATE'">
                    <span v-if="data.row.PROCESS_DATE" :title="data.row.PROCESS_DATE">
                     {{ $options.filters.formatDate(data.row.PROCESS_DATE) }}   
                    </span>
                    <span v-else>--</span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'MINUTES_WORKED'">
                    <span class="textalignright paddingright5">{{ data.row.MINUTES_WORKED }}</span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'FEET_LOCATED'">
                    <span class="textalignright paddingright5">{{ data.row.FEET_LOCATED }}</span>
                </template>
            </template>
        </tg-list>
         <ManageColumnItems v-if="IsChangeLineItem" :ColumnIds="ColumnIds" :reqFrom="reqFrom"></ManageColumnItems>
         <EditException v-if="IsEditException" :ColumnIds="ColumnIds" :ClientId="ClientId" :IsProcessed="IsProcessed" :requestFrom="requestFrom"></EditException>
           <transition name="modal">
            <div class="my-popups" v-if="IsViewTicket">
                <loader :is-visible="isLoading"></loader>
                <div class="modal my-popups right fade d-block" :class="{ show: isShown }">
                    <div role="document" class="modal-dialog" style="max-width: 1300px !important;">
                        <div class="modal-content">
                            <div class="modal-header">
                                <h4 class="modal-title">{{ $t('TicketImage') }}</h4>

                                <button type="button" class="close" v-on:click="CloseTemplate">
                                    <em class="fa fa-times" aria-hidden="true"></em>
                                </button>

                            </div>

                           <div class="modal-body">
                                <div class="col-md-12">
                                    <div class="listing" v-if="TicketContent">
                                        <div
                                            v-html="TicketContent"
                                            class="col-12 p-0"
                                            style="min-height: 440px;white-space: pre-line;">
                                        </div>
                                    </div>
                                    <div v-else class="listing text-danger text-center border-0">
                                        {{ $t("NorecordfoundText") }}
                                    </div>

                                </div>
                            </div>
                            <div class="modal-footer">
                                <button @click="CloseTemplate" class="btn btn-danger">
                                    <em class="fa fa-times pr-2" aria-hidden="true"></em> {{ $t('Cancel') }}
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </transition>
    </section>
</template>

<script>
import { locateBillingService } from "../../../services/locateBillingService";
import DataService from "../../../services/DataService";
import Schema from "./FlagRecordsSchema";
import ManageColumnItems from "../../BillingValidationData/components/ManageColumnItems.vue";
import EditException from "../../BillingValidationData/components/EditException.vue";

export default {
    name: "FlagRecords",
    components: { ManageColumnItems, EditException },
    data() {
        return {
            isLoading: false,
            PageSize: 10,
            PageNumber: 1,
            isPaged: 1,
            TotalPages: 0,
            widgets: [],
            LegendArray: [],
            SortBy: '',
            SortExp: '',
            CurrentPage: 1,
            TotalRecords: 0,
            ListingData: [],
            Buttons: Schema.buttons,
            leftSearchFields: Schema.leftsearchSchema,
            listActions: Schema.listActions,
            Headers: Schema.headerSchema,
            searchCondition: "",
            selectedUtilities: [],
            groupedUtilities: [
                //   { text: 'Utility A', value: 'ua' ,accountName:'Electric',accountNumber:'12345890',customerName:'Customer A',customerNumber:'1234567890',status:'Active'},
                //   { text: 'Utility B', value: 'ub',accountName:'Electric',accountNumber:'12347891',customerName:'Customer B',customerNumber:'1234567891',status:'Active' },
                //   { text: 'Utility C', value: 'uc' ,accountName:'Water',accountNumber:'12347892',customerName:'Customer C',customerNumber:'1234567892',status:'Active' },
                //   { text: 'Utility D', value: 'ud',accountName:'Water',accountNumber:'12345893',customerName:'Customer D',customerNumber:'1234567893',status:'Active' },
                //   { text: 'Utility E', value: 'ue',accountName:'Electric',accountNumber:'12567894',customerName:'Customer E',customerNumber:'1234567894',status:'Active' },
                //   { text: 'Utility F', value: 'uf',accountName:'Electric',accountNumber:'12567895',customerName:'Customer F',customerNumber:'1234567895',status:'Active' }
                
            ],
            IsChangeLineItem: false,
            ColumnIds: '',
            reqFrom: "catchall",
            IsEditException: false,
            ClientId: '',
            IsProcessed:0,
            TicketNumber: '',
            TransmissionId: '',
            IsViewTicket: false,
            TicketContent: '',
            requestFrom: '',
            isShown:false,
            isSupervisor:false
        }
    },
     created: async function () {
        var vm = this;
        var UserDateFormat= vm.GetUserInfo.DateFormat == ""? 'MM/DD/YYYY' : vm.GetUserInfo.DateFormat;
        if (vm.leftSearchFields?.length > 0) {
            vm.leftSearchFields.find(f => f.fieldName === 'Work_Date').format= UserDateFormat;
            vm.leftSearchFields.find(f => f.fieldName === 'ProcessDate').format= UserDateFormat;
            vm.leftSearchFields.find(f => f.fieldName === 'ClientName').onChange= vm.onSelectionChange;
            vm.leftSearchFields.find(f => f.fieldName === 'Work_Date').onChange= vm.setTimerDate;
            vm.leftSearchFields.find(f => f.fieldName === 'ProcessDate').onChange= vm.setProcessTimerDate;
        }
        vm.Headers.forEach(element => {
            element.DISPLAY_NAME = vm.$t(element.DISPLAY_NAME);
        });
        await vm.BindSupervisor();
        await vm.GetEmailConfigurationSetting(); 
        Schema.bindleftCommonSearchdropdown(this);  
        await vm.fetchclientlist();
        //await vm.FetchFlagRecords();
    },
    mounted() {
        this.$nextTick(() => {
            setTimeout(() => {
                this.isShown = true;  // adds .show ? triggers transform transition
            }, 50);
        });
    },
    methods: {
      setTimerDate(x) {
            this.applySecondDate(x);
        },

        setProcessTimerDate(x) {
            this.applySecondDate(x);
        },
       applySecondDate(x) {
            var vm = this;
            x.datePickerConfig.maxDate = '';

            const today = new Date();
            today.setHours(0, 0, 0, 0);

            const parseDate = (val) => {
                if (val instanceof Date && !isNaN(val.getTime())) {
                    const d = new Date(val);
                    d.setHours(0, 0, 0, 0);
                    return d;
                }

                if (typeof val === 'string' && val) {
                    const parts = val.split(/[\/\-]/);
                    if (parts.length === 3) {
                        const month = parseInt(parts[0], 10) - 1;
                        const day   = parseInt(parts[1], 10);
                        const year  = parseInt(parts[2], 10);

                        const d = new Date(year, month, day);
                        d.setHours(0, 0, 0, 0);
                        return isNaN(d.getTime()) ? null : d;
                    }
                }
                return null;
            };

            const valueDate  = parseDate(x.value);
            const secondDate = parseDate(x.secondValue);

            // ✅ If secondValue already exists
            if (secondDate) {
                if (valueDate && valueDate > secondDate) {
                    x.secondValue = vm.$options.filters.formatDate(valueDate);
                }else{
                    x.secondValue = vm.$options.filters.formatDate(secondDate);
                }
                // else → keep existing secondValue
                return;
            }

            // ✅ If secondValue does NOT exist yet
            if (valueDate && valueDate > today) {
                x.secondValue = vm.$options.filters.formatDate(valueDate);
            } else {
                x.secondValue = vm.$options.filters.formatDate(today);
            }
        },


        leftCommonSearch: function (value) {
            var vm = this;
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;
            if (typeof value.searchCondition != 'undefined') {
                if (value.searchConditionJson != '') {
                    this.searchCondition = value.searchConditionJson;
                } else {
                    this.searchCondition = value.searchCondition || "";
                    this.leftSearchFields.find(f => f.fieldName === 'UtilityName').listOptions = [];

                }
            } else {
                this.searchCondition = "";
            }
            if (this.searchCondition) {
                this.searchCondition = this.searchCondition.replace(/WorkDate=([^&]+)/, function (_, val) {
                    let [from, to] = val.split("|");
                    if (from && !to) {
                        to = new Date().toISOString().split('T')[0];
                    }
                    return `workDateFrom=${from}&workDateTo=${to}`;
                });
                this.searchCondition = this.searchCondition.replace(/ProcessDate=([^&]+)/, function (_, val) {
                    let [from, to] = val.split("|");
                    if (from && !to) {
                        to = new Date().toISOString().split('T')[0];
                    }
                    return `processDateFrom=${from}&processDateTo=${to}`;
                });
            }
            if(value.searchCondition=='' && value.searchConditionJson==''){
                vm.ListingData = [];
                vm.TotalRecords = 0;
                vm.PageNumber = 1;
                vm.refreshKey += 1;
            }else{
                this.FetchFlagRecords();
            }
        },
        onSelectionChange(value,x) {
        // Ensure value is an array for multiple mode
            var vm = this;
            //vm.isLoading = true;
            var url = `clientId=${x}&configId=&reqFrom=&clientIds=`;
            locateBillingService.getUtilityList(url).then(response => {
                //vm.isLoading = false;
                let SelectedClientList=[];
                    var UtilityList = response.data;
                    if (UtilityList != null) {
                        UtilityList.forEach(item => {
                            let obj = {
                                description: null,
                                displayValue: item.UTILITY_NAME,
                                groupText: null,
                                groupValue: null,
                                metaData: null,
                                text: item.UTILITY_NAME,
                                value: item.UTILITY_ID   
                            };
                            SelectedClientList.push(obj);
                        });
                        vm.leftSearchFields.find(f => f.fieldName === 'UtilityName').listOptions = SelectedClientList;
                        vm.groupedUtilities=vm.UtilityList;
                    }
            }).catch(error => {
                //vm.isLoading = false;
                vm.UtilityList = []; 
                vm.leftSearchFields.find(f => f.fieldName === 'UtilityName').value='';
                vm.leftSearchFields.find(f => f.fieldName === 'UtilityName').listOptions = [];
            }).finally(() => {
                //vm.isLoading = false;
            });
        },
        renderActions: function (row) {
            var self = this;
            let rtnActionArray = [];
            self.listActions.forEach(actionItem => {
                let action = { ...actionItem };
                switch (action.title) {
                    case 'TicketImage':
                        action.isVisible = true;
                        break;
                    case 'Edit':
                        action.isVisible = true;
                        break;
                    default: {
                        action.isVisible = true;
                    }
                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },
        pagerMethod: function (value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchFlagRecords();
        },
        actionButtonClick: function (callbackfunction, item) {
            switch (callbackfunction) {
                case 'ViewTicketImage':
                    this.viewTicketImage(item);
                    break;
                case 'EditRecord':
                    this.editRecord(item);
                    break;
            }
        },
        commonHeaderButtonClick: function (event) {
            switch (event.callbackfunction) {
                case "Process":
                    this.ProcessColumnItems();
                    break;
                case "DoNotBill":
                    this.DoNotProcessLineItems();
                    break;
                case "Update":
                    this.ChangeColumnItems();
                    break;
                case "FlagSummaryReport":
                    this.FlagSummaryReport();
                    break;

            }
        },
        FlagSummaryReport(){
            var vm=this;
            var privilegeParams = `controller=InvoiceReport&action=FlagSummaryReport`;
            DataService.CheckPrivilege(privilegeParams).then(function (response) {
            if (response.data) {
                window.location.href = '/InvoiceReport/Index?tab=Flag%20Summary%20Report';
            //vm.$router.push('/InvoiceReport/Index');
            }
            else {
                vm.ShowAlert(vm.$t('UnAuthorized'), "warning", vm.$t('Alert'));
                return false;
            }
            });
        },
        ProcessColumnItems: async function (event) {
            var vm = this;
            var val = "";
            $('.chkItems:checkbox:checked').not("[id^='chkAll_0']").each(async function () {
                if (val.length > 0)
                    val += ',';
                val += $(this).val();
            });
            if (val.length > 0) {
            var privilegeParams = `controller=FlagRecords&action=SaveColumnItems`;
            await DataService.CheckPrivilege(privilegeParams).then(function (response) {
            if (response.data) {
                 vm.confirmR(vm.$t(`ConfirmProcessFlagRecords`), true, false, function () {
                    var postJSON = {
                        value: '',
                        fieldName: '',
                        lineIds: val,
                        reqFrom:  'process',
                        setClient: 0,
                        beSbaId: 0
                    };
                    locateBillingService.SaveColumnItems(postJSON).then(async function (response) {
                        if (response.data.msg == 'Success') {
                            await vm.FetchFlagRecords();
                            await vm.$nextTick();
                           vm.ShowAlert(vm.$t('RecordUpdatedSuccessfully'), "success", true, vm.$t("Alert"));
                        }
                        else {
                            vm.ShowAlert(vm.$t('DeletedError', [vm.$t('WorkCode')]), "failure", true, vm.$t("Alert"));
                        }

                    });
                });
                }
                else {
                    vm.ShowAlert(vm.$t('UnAuthorized'), "warning", vm.$t('Alert'));
                    return false;
                }
                });
            }
            else {
                vm.ShowAlert(vm.$t("SelectanyrecordtoChangeFlagRecords"), "warning", true, vm.$t("Alert"));
            }
        },
        DoNotProcessLineItems: function (event) {
            var vm = this;
            var val = "";
            $('.chkItems:checkbox:checked').not("[id^='chkAll_0']").each(async function () {
                if (val.length > 0)
                    val += ',';
                val += $(this).val();
            });
            if (val.length > 0) {
            var privilegeParams = `controller=FlagRecords&action=DoNotProcessLineItems`;
            DataService.CheckPrivilege(privilegeParams).then(function (response) {
            if (response.data) {
                 vm.confirmR(vm.$t(`ConfirmPurgesFlagRecords`), true, false, function () {
                    var postJSON = {
                        value: '',
                        fieldName: '',
                        lineIds: val
                    };
                    locateBillingService.DoNotProcessLineItems(postJSON).then(async function (response) {
                        if (response.data.msg == 'Success') {
                           await vm.FetchFlagRecords();
                           await vm.$nextTick();
                           vm.ShowAlert(vm.$t('RecordUpdatedSuccessfully'), "success", true, vm.$t("Alert"));
                        }
                        else {
                            vm.ShowAlert(vm.$t('DeletedError', [vm.$t('WorkCode')]), "failure", true, vm.$t("Alert"));
                        }
                    });
                });
                }
                else {
                    vm.ShowAlert(vm.$t('UnAuthorized'), "warning", vm.$t('Alert'));
                    return false;
                }
                
                });
            }
            else {
                vm.ShowAlert(vm.$t("SelectanyrecordtoChangeFlagRecords"), "warning", true, vm.$t("Alert"));
            }
        },
         ChangeColumnItems: function (event) {
            var vm = this;
            var val = "";
            $('.chkItems:checkbox:checked').not("[id^='chkAll_0']").each(async function () {
                if (val.length > 0)
                    val += ',';
                val += $(this).val();
            });
            if (val.length > 0) {
                
            var privilegeParams = `controller=FlagRecords&action=ChangeColumnItems`;
            DataService.CheckPrivilege(privilegeParams).then(function (response) {
            if (response.data) {
                vm.ColumnIds= val;
                vm.IsChangeLineItem = !vm.IsChangeLineItem;
                }
                else {
                    vm.ShowAlert(vm.$t('UnAuthorized'), "warning", vm.$t('Alert'));
                    return false;
                }
                });
            }
            else {
                vm.ShowAlert(vm.$t("SelectanyrecordtoChangeFlagRecords"), "warning", true, vm.$t("Alert"));
            }
        },

        sortdata: function (sortBy) {
            this.SortBy = sortBy;
            if (this.SortExp == "") {
                this.SortExp = "ASC";
            } else if (this.SortExp == "ASC") {
                this.SortExp = "DESC";
            } else {
                this.SortExp = "ASC";
            }
            this.FetchFlagRecords();
        },
        FetchFlagRecords: async function () {
            var vm = this;
            vm.isLoading = true;
            var url = `pageSize=${vm.PageSize}&pageNum=${vm.PageNumber}&sortBy=${vm.SortBy}&sortExp=${vm.SortExp}`;
            
            // Add search condition if available
            if (vm.searchCondition) {
                url += `&${vm.searchCondition}`;
            }
            await locateBillingService.GetFlagRecords(url).then((response) => {
                vm.isLoading = false;
                if(response.data.result){
                    vm.ListingData=JSON.parse(response.data.result)
                }
                if (vm.ListingData  && vm.ListingData.length > 0) {
                    vm.ListingData.forEach((item) => {
                        if (item.TRANSMIT_DATE) {
                            item.TRANSMIT_DATE = new Date(item.TRANSMIT_DATE);
                        }
                        if (item.WORK_DATE) {
                            item.WORK_DATE = new Date(item.WORK_DATE);
                        }
                        if (item.PROCESS_DATE) {
                            item.PROCESS_DATE = new Date(item.PROCESS_DATE);
                        }
                    });
                    vm.TotalRecords = vm.ListingData[0].TOTAL_RECORDS || vm.ListingData[0].TOTALRECORDS || 0;
                    vm.TotalPages = Math.ceil(vm.TotalRecords / vm.PageSize);
                    vm.CurrentPage = vm.PageNumber;
                } else {
                    vm.ListingData = [];
                    vm.TotalRecords = 0;
                }
            }).catch((error) => {
                vm.isLoading = false;
                vm.ListingData = [];
                vm.TotalRecords = 0;
                console.error('Error fetching flag records:', error);
            });
        },
        getFlagClass(flag) {
            if (!flag) return '';
            const flagUpper = flag.toUpperCase().trim();
            if (flagUpper === 'R') {
                return 'bg-danger py-1 px-1 text-white w-100 d-block text-center';
            } else if (flagUpper === 'Y') {
                return 'bg-warning py-1 px-1 text-white w-100 d-block text-center';
            } else if (flagUpper === 'G') {
                return 'bg-success py-1 px-1 text-white w-100 d-block text-center';
            }
            return '';
        },
        CloseTemplate: function () {
            var vueObj = this;
            vueObj.IsViewTicket = false;
        },
        viewTicketImage: function(item) {
            var vm =this;
            var privilegeParams = `controller=FlagRecords&action=ViewTicketImage`;
            DataService.CheckPrivilege(privilegeParams).then(function (response) {
            if (response.data) {
            vm.TicketNumber= item.TICKETNUMBER;
            vm.TransmissionId= item.TRANSMISSION_ID;
            vm.IsViewTicket= !vm.IsViewTicket;
            var url = `TicketNumber=${vm.TicketNumber}&TransmissionId=${vm.TransmissionId}`
              locateBillingService.ViewTicketImage(url).then((response) => {
                if (response.data.length>0) {
                    vm.TicketContent = response.data[0].RAW_IMAGE;
                }
            });
             }
            else {
                vm.ShowAlert(vm.$t('UnAuthorized'), "warning", vm.$t('Alert'));
                return false;
            }
            });
        },
        editRecord(item) {
            var vm =this;
            var privilegeParams = `controller=FlagRecords&action=EditException`;
            DataService.CheckPrivilege(privilegeParams).then(function (response) {
            if (response.data) {
            vm.ColumnIds= item.COLUMN_ID;
            vm.ClientId=item.CLIENT_ID;
            vm.IsEditException = !vm.IsEditException;
            }
            else {
                vm.ShowAlert(vm.$t('UnAuthorized'), "warning", vm.$t('Alert'));
                return false;
            }
            });
        },
        fetchclientlist: function () {
            var vm = this;
            vm.isLoading = true;
            var url = `reqFrom=CUSTOM&screenName=FLAG`;
            locateBillingService.getClientList(url).then(response => {
                vm.isLoading = false;
                vm.clientList = response.data.items;
                vm.leftSearchFields.find(f => f.fieldName === 'ClientName').listOptions = vm.clientList;
                vm.groupedUtilities=vm.clientList;
            }).catch(error => {
                vm.isLoading = false;
                vm.clientList = []; 
                vm.leftSearchFields.find(f => f.fieldName === 'ClientName').listOptions = [];
                console.error('Error fetching client list:', error);
            }).finally(() => {
                vm.isLoading = false;
            });
        },

         BindSupervisor: async function () {
            var vm = this;           
            await DataService.CheckIsSupervisor().then(response => {
                if (response.data) {                      
                    vm.isSupervisor=response.data;
                }
            });
        },

         async GetEmailConfigurationSetting() {
            var vm = this;
            var params = `_CompanyId=${vm.GetUserInfo.CompanyId}&userId=${vm.GetUserInfo.ID}&moduleName=User&configkey=CanViewAllContractData`;
            await DataService.GetEmailConfigurationSetting(params)
                .then(response => {
                    if (response.data && response.data.length > 0)
                    {
                        if(response.data[0].CONFIG_DATA_VALUE.toLowerCase() === 'yes' || vm.GetUserInfo.UserType.toLowerCase()=='ca' || vm.isSupervisor){                           
                            Schema.bindleftCommonSearchdropdown(this,"BILLER");                      
                        } else {
                          vm.leftSearchFields = vm.leftSearchFields.filter(f => f.fieldName !== 'Biller');
                        }
                    }
                })
                .catch(err => {
                    console.log(err);
                });
        },

    }
}
</script>

<style scoped>
.textalignright {
    text-align: right;
}
.paddingright5 {
    padding-right: 5px;
}
</style>
